+/// Generate a C-callable export wrapper for a struct method
+/// This allows the method to be called from C/external code via dlsym
+fn genExportWrapper(self: *NativeCodegen, class_name: []const u8, method_name: []const u8, func: ast.Node.FunctionDef) CodegenError!void {
+    // Export wrapper signature: export fn ClassName_methodName(args...) callconv(.C) ReturnType
+    try self.emitFmt("export fn {s}_{s}(", .{ class_name, method_name });
+
+    // Generate parameters (skip 'self' which is the first parameter)
+    var param_count: usize = 0;
+    for (func.args) |arg| {
+        // Skip 'self' parameter
+        if (std.mem.eql(u8, arg.name, "self")) continue;
+
+        if (param_count > 0) try self.emit(", ");
+
+        // For simplicity, use f64 for numeric types and [*]f64 for arrays
+        // This provides a C-compatible ABI
+        try self.emitFmt("{s}: ", .{arg.name});
+        if (arg.type_annotation) |type_name| {
+            if (std.mem.eql(u8, type_name, "float")) {
+                try self.emit("f64");
+            } else if (std.mem.eql(u8, type_name, "int")) {
+                try self.emit("i64");
+            } else if (std.mem.eql(u8, type_name, "list") or std.mem.startsWith(u8, type_name, "list[")) {
+                // list or list[float] -> [*]f64
+                try self.emit("[*]f64");
+            } else {
+                try self.emit("*anyopaque"); // Generic pointer for unknown types
+            }
+        } else {
+            // No annotation - assume f64 for numeric compatibility
+            try self.emit("f64");
+        }
+        param_count += 1;
+    }
+
+    // If there were array parameters, add a length parameter
+    var has_array_param = false;
+    for (func.args) |arg| {
+        if (std.mem.eql(u8, arg.name, "self")) continue;
+        if (arg.type_annotation) |type_name| {
+            if (std.mem.eql(u8, type_name, "list") or std.mem.startsWith(u8, type_name, "list[")) {
+                has_array_param = true;
+                break;
+            }
+        }
+    }
+    if (has_array_param) {
+        if (param_count > 0) try self.emit(", ");
+        try self.emit("len: usize");
+    }
+
+    // Return type - use .c for C calling convention
+    try self.emit(") callconv(.c) ");
+
+    // Determine return type from annotation
+    if (func.return_type) |ret_type| {
+        if (std.mem.eql(u8, ret_type, "float")) {
+            try self.emit("f64");
+        } else if (std.mem.eql(u8, ret_type, "int")) {
+            try self.emit("i64");
+        } else {
+            try self.emit("f64"); // Default to f64
+        }
+    } else {
+        try self.emit("f64"); // Default return type
+    }
+
+    try self.emit(" {\n");
+    self.indent_level += 1;
+
+    // Generate call to struct method
+    // The struct method has signature: fn(allocator, self, args...)
+    // For static functions without self state, pass undefined for self
+    try self.emitIndent();
+    try self.emitFmt("return {s}.{s}(__global_allocator, undefined", .{ class_name, method_name });
+
+    // Forward parameters
+    for (func.args) |arg| {
+        if (std.mem.eql(u8, arg.name, "self")) continue;
+
+        // Wrap pointer parameters in slices using length
+        if (arg.type_annotation) |type_name| {
+            if (std.mem.eql(u8, type_name, "list") or std.mem.startsWith(u8, type_name, "list[")) {
+                try self.emitFmt(", {s}[0..len]", .{arg.name});
+            } else {
+                try self.emitFmt(", {s}", .{arg.name});
+            }
+        } else {
+            try self.emitFmt(", {s}", .{arg.name});
+        }
+    }
+
+    try self.emit(") catch 0.0;\n");
+
+    self.indent_level -= 1;
+    try self.emitIndent();
+    try self.emit("}\n\n");
 }

